&lt;p&gt;Voici un composant &lt;code&gt;Carte&lt;/code&gt; :&lt;/p&gt;&lt;pre&gt;&lt;code&gt;function Carte({ children }) {
  return &lt;div className="border p-4 rounded shadow"&gt;{children}&lt;/div&gt;;
}&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Quel est le résultat de &lt;code&gt;&lt;Carte&gt;&lt;p&gt;Bonjour&lt;/p&gt;&lt;/Carte&gt;&lt;/code&gt; ?&lt;/p&gt;

&lt;p&gt;Voici un composant &lt;code&gt;Liste&lt;/code&gt; :&lt;/p&gt;&lt;pre&gt;&lt;code&gt;function Liste({ items, renderItem }) {
  return &lt;ul&gt;{items.map(renderItem)}&lt;/ul&gt;;
}&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Quel pattern est utilisé ici ?&lt;/p&gt;
